using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    #region CreateOrder – Happy Path

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsOrderWithSummedTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 3 },
            new() { ProductName = "Doohickey", Price = 5.00m, Quantity = 10 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        // 10*1 + 25.50*3 + 5*10 = 10 + 76.50 + 50 = 136.50
        Assert.AreEqual(136.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_ReturnsOrderWithNonNullId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("customer-abc", items);

        // Assert
        Assert.AreEqual("customer-abc", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_ReturnsOrderWithCorrectItems()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Alpha", Price = 1.00m, Quantity = 1 },
            new() { ProductName = "Beta", Price = 2.00m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreSame(items, order.Items);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        var before = DateTime.UtcNow;

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before, $"CreatedAt {order.CreatedAt} should be >= {before}");
        Assert.IsTrue(order.CreatedAt <= after, $"CreatedAt {order.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_EachOrderGetsUniqueId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder – Total Calculation with DataRow

    [TestMethod]
    [DataRow(10.00, 1, 10.00, DisplayName = "Single item, quantity 1")]
    [DataRow(7.50, 4, 30.00, DisplayName = "Single item, quantity 4")]
    [DataRow(0.01, 100, 1.00, DisplayName = "Penny item, quantity 100")]
    [DataRow(999.99, 1, 999.99, DisplayName = "High price, quantity 1")]
    public void CreateOrder_SingleItemVariousInputs_CalculatesTotalCorrectly(
        double price, int quantity, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion

    #region CreateOrder – Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", items));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region CreateOrder – Order is stored

    [TestMethod]
    public void CreateOrder_ValidInput_OrderIsRetrievableByGetOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-1", items);
